mapper.insert:
INSERT INTO `user` (
    id, username, password_hash, real_name, status, created_at, updated_at, is_deleted
) VALUES (
    #{id}, #{username}, #{passwordHash}, #{realName}, #{status}, #{createdAt}, #{updatedAt}, 0
)

INSERT INTO `role` (
    id, role_code, role_name, status, created_at, updated_at, is_deleted
) VALUES (
    #{id}, #{roleCode}, #{roleName}, 1, #{createdAt}, #{updatedAt}, 0
)

INSERT INTO `user_role` (
    id, user_id, role_id, status, created_at, updated_at, is_deleted
) VALUES (
    #{id}, #{userId}, #{roleId}, 1, #{createdAt}, #{updatedAt}, 0
)

mapper.update:
UPDATE `user`
SET last_login_at = #{lastLoginAt},
    updated_at = #{updatedAt}
WHERE id = #{userId}

UPDATE `user`
SET real_name  = #{realName},
    updated_at = #{updatedAt}
WHERE id = #{userId}

UPDATE `user`
SET password_hash = #{passwordHash},
    updated_at    = #{updatedAt}
WHERE id = #{userId}

UPDATE `user`
SET real_name  = #{realName},
    student_no = #{studentNo},
    updated_at = #{updatedAt}
WHERE id = #{userId}

UPDATE `user`
SET phone      = #{phone},
    email      = #{email},
    updated_at = #{updatedAt}
WHERE id = #{userId}
